# scripts/sandbox_key_pool.py
"""Assign an API key from the pool to a PR sandbox."""
import json, pathlib, sys

POOL_PATH = pathlib.Path("sandbox_key_pool.json")

def claim_key(pr_number: int) -> str:
    pool = json.loads(POOL_PATH.read_text())
    available = [k for k in pool["keys"] if not k.get("claimed_by")]
    if not available:
        raise RuntimeError("No sandbox API keys available — wait for a PR to close")
    key = available[0]
    key["claimed_by"] = pr_number
    POOL_PATH.write_text(json.dumps(pool, indent=2))
    return key["key_name"]   # secret name in GitHub, not the key value itself

def release_key(pr_number: int):
    pool = json.loads(POOL_PATH.read_text())
    for k in pool["keys"]:
        if k.get("claimed_by") == pr_number:
            k["claimed_by"] = None
    POOL_PATH.write_text(json.dumps(pool, indent=2))

if __name__ == "__main__":
    action = sys.argv[1]   # "claim" or "release"
    pr = int(sys.argv[2])
    if action == "claim":
        print(claim_key(pr))
    elif action == "release":
        release_key(pr)
